"use client";

import { useState } from "react";
import { ForgotPasswordSheet } from "./forgot-password-sheet";
import { Login } from "./login";

export const LoginPage = () => {
    const [forgotOpen, setForgotOpen] = useState(false);

    return (
        <>
            <Login
                onForgotPassword={() => setForgotOpen(true)}
                onSwitchToSignUp={() => {
                    // Hook this into your router or sign-up state.
                }}
            />
            <ForgotPasswordSheet open={forgotOpen} onOpenChange={setForgotOpen} />
        </>
    );
};

import { Button } from "@/components/ui/button";
import {
    Card,
    CardAction,
    CardContent,
    CardDescription,
    CardHeader,
    CardTitle,
} from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";

export type LoginProps = {
    onForgotPassword?: () => void;
    onSwitchToSignUp?: () => void;
};

export const Login = ({ onForgotPassword, onSwitchToSignUp }: LoginProps) => {
    return (
        <Card className="w-full max-w-md">
            <CardHeader>
                <CardTitle>Login</CardTitle>
                <CardDescription>Enter your details to login to your account.</CardDescription>
                <CardAction>
                    <Button type="button" variant="link" onClick={onSwitchToSignUp}>
                        Sign Up
                    </Button>
                </CardAction>
            </CardHeader>
            <CardContent>
                <form className="space-y-6">
                    <div className="grid gap-2">
                        <Label htmlFor="email">Email</Label>
                        <Input id="email" type="email" placeholder="m@example.com" required />
                    </div>
                    <div className="grid gap-2">
                        <div className="flex items-center">
                            <Label htmlFor="password">Password</Label>
                            <Button
                                type="button"
                                variant="link"
                                className="ml-auto h-auto p-0 text-sm"
                                onClick={onForgotPassword}
                            >
                                Forgot your password?
                            </Button>
                        </div>
                        <Input id="password" type="password" required />
                    </div>
                    <Button type="submit" className="w-full">
                        Continue
                    </Button>
                </form>
            </CardContent>
        </Card>
    );
};

// Backward-compatible alias while transitioning from the previous exported name.
export const Login1 = Login;

"use client";

import { Button } from "@/components/ui/button";
import {
    Sheet,
    SheetClose,
    SheetContent,
    SheetDescription,
    SheetFooter,
    SheetHeader,
    SheetTitle,
} from "@/components/ui/sheet";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";

export type ForgotPasswordSheetProps = {
    open: boolean;
    onOpenChange: (open: boolean) => void;
};

export const ForgotPasswordSheet = ({ open, onOpenChange }: ForgotPasswordSheetProps) => {
    return (
        <Sheet open={open} onOpenChange={onOpenChange}>
            <SheetContent side="right" className="sm:max-w-md">
                <SheetHeader>
                    <SheetTitle>Reset password</SheetTitle>
                    <SheetDescription>
                        Enter your email and we will send you a reset link.
                    </SheetDescription>
                </SheetHeader>

                <form className="mt-6 space-y-4">
                    <div className="grid gap-2">
                        <Label htmlFor="reset-email">Email</Label>
                        <Input
                            id="reset-email"
                            type="email"
                            placeholder="m@example.com"
                            required
                        />
                    </div>

                    <SheetFooter className="mt-6 gap-2 sm:justify-start">
                        <Button type="submit">Send reset link</Button>
                        <SheetClose asChild>
                            <Button type="button" variant="ghost">
                                Cancel
                            </Button>
                        </SheetClose>
                    </SheetFooter>
                </form>
            </SheetContent>
        </Sheet>
    );
};
